import{_ as i,o as t,c as l,ae as e}from"./chunks/framework.EHGTsUvI.js";const u=JSON.parse('{"title":"进阶 Prompt 策略：为什么 Few-Shot、CoT 和结构化输出能让结果更稳","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/advanced-prompting.md","filePath":"ai-tutorial/advanced-prompting.md"}'),o={name:"ai-tutorial/advanced-prompting.md"};function r(p,a,n,s,h,d){return t(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="进阶-prompt-策略-为什么-few-shot、cot-和结构化输出能让结果更稳" tabindex="-1">进阶 Prompt 策略：为什么 Few-Shot、CoT 和结构化输出能让结果更稳 <a class="header-anchor" href="#进阶-prompt-策略-为什么-few-shot、cot-和结构化输出能让结果更稳" aria-label="Permalink to &quot;进阶 Prompt 策略：为什么 Few-Shot、CoT 和结构化输出能让结果更稳&quot;">​</a></h1><blockquote><p>很多人学 Prompt，学到最后会陷入一种很微妙的幻觉：好像只要把话说得更完整、更“像专家”、更像一套咒语，模型就会自动变得可靠。</p><p>真实工程里，事情远没有这么浪漫。多数时候，模型出错不是因为你不够会“写提示词文学”，而是因为你把一个本来需要示例、推导、校验和系统分工的问题，粗暴地压成了一段自然语言命令。</p></blockquote><p>我越来越倾向于把进阶 Prompt 看成一门“输入建模”的工作，而不是一门“措辞美化”的技巧。</p><p>所谓进阶，不是让 Prompt 变长，而是让模型在更好的输入结构里工作：</p><ul><li>它需要什么示例，才能明白你真正的判断口径；</li><li>它需要怎样的中间步骤，才能别在复杂问题上跳步；</li><li>它需要什么输出边界，才能让系统接得住；</li><li>它什么时候根本不该继续靠 Prompt 硬扛，而该交给检索、工具或工作流。</li></ul><div class="info custom-block"><p class="custom-block-title">这篇文章会回答什么</p><ul><li>Few-Shot 为什么常常比“写十条规则”更有效</li><li>Chain of Thought 到底帮了什么忙，又在哪些场景会帮倒忙</li><li>为什么结构化输出几乎是 Prompt 工程进入生产环境的分水岭</li><li>如何判断一个问题该继续打磨 Prompt，还是该换成 RAG、Tool Use 或多阶段编排</li></ul></div><h2 id="_1-先说结论-大多数-prompt-问题-本质上不是-不会说话-而是-不会建模" tabindex="-1">1. 先说结论：大多数 Prompt 问题，本质上不是“不会说话”，而是“不会建模” <a class="header-anchor" href="#_1-先说结论-大多数-prompt-问题-本质上不是-不会说话-而是-不会建模" aria-label="Permalink to &quot;1. 先说结论：大多数 Prompt 问题，本质上不是“不会说话”，而是“不会建模”&quot;">​</a></h2><p>举一个很常见的业务场景。</p><p>假设你要做一个内部审批助手，目标不是闲聊，而是让它判断“员工离职时，未休年假折算是否符合制度”。这类问题看起来像问答，实际上同时包含了四层难点：</p><ol><li>规则本身有多条前置条件；</li><li>一部分条件来自制度文本，一部分来自员工实时信息；</li><li>结果必须给出理由，而不是只给一个“是 / 否”；</li><li>输出最后要被系统消费，最好还能形成结构化记录。</li></ol><p>如果你只是写一句：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请根据公司制度判断这名员工是否可以折算年假，并给出准确结论。</span></span></code></pre></div><p>模型当然也会回答，但这种回答往往有两个毛病：</p><ul><li>它会把“听起来合理”误当成“经过验证”；</li><li>它没有被迫暴露自己的判断路径，所以你很难知道它错在了哪一步。</li></ul><p>这时候继续加形容词，比如“请严谨、专业、认真、全面地分析”，收益通常已经很有限。因为真正缺的不是语气，而是三样东西：</p><ul><li><strong>示例</strong>：告诉它什么叫“符合你们组织口径的判断”；</li><li><strong>步骤</strong>：告诉它哪些条件必须先拆出来检查；</li><li><strong>结构</strong>：告诉它最终答案必须如何组织，方便系统验证。</li></ul><p>这三样东西，分别对应 Few-Shot、CoT 和结构化输出。</p><h2 id="_2-few-shot-真正厉害的地方-不是-举例子-而是-对齐判例" tabindex="-1">2. Few-Shot 真正厉害的地方，不是“举例子”，而是“对齐判例” <a class="header-anchor" href="#_2-few-shot-真正厉害的地方-不是-举例子-而是-对齐判例" aria-label="Permalink to &quot;2. Few-Shot 真正厉害的地方，不是“举例子”，而是“对齐判例”&quot;">​</a></h2><p>很多人第一次接触 Few-Shot，会把它理解成“在 Prompt 前面多放几个样例”。这个说法没错，但不够准。</p><p>Few-Shot 真正有价值的地方，在于它像在给模型看“判例”。</p><p>你不是单纯告诉它规则，而是在告诉它：</p><ul><li>什么样的输入值得注意；</li><li>哪些细节其实是关键；</li><li>你希望它如何组织判断过程；</li><li>在边界场景下，你们团队到底偏保守还是偏激进。</li></ul><h3 id="_2-1-为什么-few-shot-常常比长篇规则更有效" tabindex="-1">2.1 为什么 Few-Shot 常常比长篇规则更有效 <a class="header-anchor" href="#_2-1-为什么-few-shot-常常比长篇规则更有效" aria-label="Permalink to &quot;2.1 为什么 Few-Shot 常常比长篇规则更有效&quot;">​</a></h3><p>因为自然语言规则很容易看起来明确，实际上却仍然留着大量解释空间。</p><p>例如你写：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请识别用户是否属于“高风险流失客户”。</span></span></code></pre></div><p>如果后面跟的是一堆抽象规则：</p><ul><li>最近活跃度下降明显</li><li>投诉频次升高</li><li>价值贡献较高但满意度下降</li></ul><p>这对人类分析师可能够用，但对模型来说，“明显”“较高”“下降”都还是模糊词。</p><p>而如果你给出 3 到 5 个高质量样例，事情会立刻不同。因为样例同时传递了：</p><table tabindex="0"><thead><tr><th>维度</th><th>规则文本</th><th>Few-Shot 示例</th></tr></thead><tbody><tr><td>概念边界</td><td>往往抽象</td><td>更具体</td></tr><tr><td>输出格式</td><td>需要额外说明</td><td>示例天然带格式</td></tr><tr><td>组织口径</td><td>容易歧义</td><td>能体现团队偏好</td></tr><tr><td>边界情况</td><td>难写清</td><td>可直接展示</td></tr></tbody></table><p>换句话说，Few-Shot 不是在“补说明”，而是在“缩小解释空间”。</p><h3 id="_2-2-few-shot-最适合什么任务" tabindex="-1">2.2 Few-Shot 最适合什么任务 <a class="header-anchor" href="#_2-2-few-shot-最适合什么任务" aria-label="Permalink to &quot;2.2 Few-Shot 最适合什么任务&quot;">​</a></h3><p>在我看来，Few-Shot 最适合那些“答案不只看知识，还看口径”的任务。</p><p>例如：</p><ul><li>情绪分类与标签判断</li><li>摘要风格统一</li><li>结构化抽取</li><li>风险分级</li><li>代码审查意见组织方式</li></ul><p>这些任务的共同点是：模型不一定缺知识，但它缺少你这套业务或团队内部的判断习惯。</p><h3 id="_2-3-few-shot-最容易踩的坑" tabindex="-1">2.3 Few-Shot 最容易踩的坑 <a class="header-anchor" href="#_2-3-few-shot-最容易踩的坑" aria-label="Permalink to &quot;2.3 Few-Shot 最容易踩的坑&quot;">​</a></h3><p>Few-Shot 之所以好用，也正因为它“教得太快”。教得快，就意味着教错也会错得很快。</p><p>最常见的几个问题是：</p><h4 id="示例太像-宣传海报-不像真实输入" tabindex="-1">示例太像“宣传海报”，不像真实输入 <a class="header-anchor" href="#示例太像-宣传海报-不像真实输入" aria-label="Permalink to &quot;示例太像“宣传海报”，不像真实输入&quot;">​</a></h4><p>很多人写示例时，会忍不住把例子写得特别整洁。现实里的用户输入明明是脏的、短的、跳跃的，但样例却像教科书。这会导致模型在真实输入下失去方向感。</p><h4 id="示例只展示常规情况-不展示边界情况" tabindex="-1">示例只展示常规情况，不展示边界情况 <a class="header-anchor" href="#示例只展示常规情况-不展示边界情况" aria-label="Permalink to &quot;示例只展示常规情况，不展示边界情况&quot;">​</a></h4><p>如果 5 个示例全是最标准的 happy path，模型在遇到模棱两可的情况时仍然会乱猜。真正有价值的示例，往往不是“最典型”的，而是“最容易出错的边缘样本”。</p><h4 id="示例的输出风格和目标系统不一致" tabindex="-1">示例的输出风格和目标系统不一致 <a class="header-anchor" href="#示例的输出风格和目标系统不一致" aria-label="Permalink to &quot;示例的输出风格和目标系统不一致&quot;">​</a></h4><p>比如你最终希望得到 JSON，但 few-shot 给的却是自然语言段落；或者你最终希望得到很短的审计结论，但样例全是长篇分析。模型通常会学到你真正展示的东西，而不是你口头要求它做的东西。</p><h3 id="_2-4-一个更实用的-few-shot-原则" tabindex="-1">2.4 一个更实用的 Few-Shot 原则 <a class="header-anchor" href="#_2-4-一个更实用的-few-shot-原则" aria-label="Permalink to &quot;2.4 一个更实用的 Few-Shot 原则&quot;">​</a></h3><p>如果你要用 Few-Shot，不妨把样例当作“最小判例库”来写。每组样例至少问自己三个问题：</p><ol><li>这是不是现实里真的会出现的输入？</li><li>它有没有覆盖容易分歧的边界？</li><li>它的输出是不是已经接近我最终想上线的格式？</li></ol><p>如果这三个问题都答不上来，样例再多也只是装饰。</p><h2 id="_3-cot-不是让模型-显得聪明-而是避免它在复杂问题上跳步" tabindex="-1">3. CoT 不是让模型“显得聪明”，而是避免它在复杂问题上跳步 <a class="header-anchor" href="#_3-cot-不是让模型-显得聪明-而是避免它在复杂问题上跳步" aria-label="Permalink to &quot;3. CoT 不是让模型“显得聪明”，而是避免它在复杂问题上跳步&quot;">​</a></h2><p>Chain of Thought（CoT）几乎是 Prompt 讨论里最容易被神化，也最容易被滥用的技术。</p><p>它真正解决的，不是所有任务，而是一类特定问题：</p><ul><li>需要多步推理；</li><li>中间步骤彼此依赖；</li><li>如果直接跳到结论，很容易错得很自然。</li></ul><p>2022 年那篇很经典的 CoT 论文讲得很直接：当模型能够先生成一串中间推理步骤时，它在算术、常识和符号推理等复杂任务上的表现会明显提升。<a href="https://arxiv.org/abs/2201.11903" target="_blank" rel="noreferrer">论文链接</a></p><p>这件事为什么重要？</p><p>因为很多模型错误，并不是“完全不会”，而是“会一点，但跳步”。它太急于给出像答案的东西，于是中间本该显式检查的环节被压扁了。</p><h3 id="_3-1-一个非常典型的错误-模型不是不会算-而是不肯老老实实展开" tabindex="-1">3.1 一个非常典型的错误：模型不是不会算，而是不肯老老实实展开 <a class="header-anchor" href="#_3-1-一个非常典型的错误-模型不是不会算-而是不肯老老实实展开" aria-label="Permalink to &quot;3.1 一个非常典型的错误：模型不是不会算，而是不肯老老实实展开&quot;">​</a></h3><p>假设你让模型判断：</p><ul><li>员工入职 8 个月；</li><li>最近一年实际工作月数 7 个月；</li><li>年假按工龄分档；</li><li>离职时不足一年按比例折算；</li><li>但试用期期间某些天数不计入折算基数。</li></ul><p>如果你让它直接给结论，它往往会做出一种很像有道理的错误：它并不会完全编造，而是在脑中把其中一两条规则省略掉。</p><p>你让它把步骤展开，本质上是在逼它：</p><ol><li>先列已知条件；</li><li>再选适用规则；</li><li>再做计算；</li><li>最后再给结论。</li></ol><p>这并不是“给模型加法术”，而是在减少它偷懒跳步的空间。</p><h3 id="_3-2-但-cot-不是万金油" tabindex="-1">3.2 但 CoT 不是万金油 <a class="header-anchor" href="#_3-2-但-cot-不是万金油" aria-label="Permalink to &quot;3.2 但 CoT 不是万金油&quot;">​</a></h3><p>这里有个非常关键的现实判断：<strong>不是所有任务都值得打开 CoT</strong>。</p><p>如果你的任务只是：</p><ul><li>简单分类</li><li>信息抽取</li><li>固定格式改写</li><li>基于明确证据的短结论</li></ul><p>强行让模型“逐步思考”，通常会带来三个副作用：</p><ul><li>响应更慢；</li><li>Token 成本更高；</li><li>输出变长，反而更难接系统。</li></ul><p>Anthropic 在最新的 Prompting Best Practices 里其实给了一个很有启发性的提醒：当模型已经具备较强 thinking 能力时，很多场景下更好的做法不是手写非常死板的推理步骤，而是给更一般化的高质量指导；过度提示反而会让模型“思考过度”，增加延迟和 token 消耗。<a href="https://platform.claude.com/docs/en/build-with-claude/prompt-engineering/claude-prompting-best-practices#leverage-thinking-and-interleaved-thinking-capabilities" target="_blank" rel="noreferrer">官方文档</a></p><p>这句话背后的意思非常值得认真理解：</p><ul><li>对旧模型或普通 GPT 型模型，显式 CoT 往往很有帮助；</li><li>对新一代 reasoning 模型，很多时候你需要的是“让它知道该认真推理”，而不是替它把每一步写死；</li><li>一旦系统对延迟和成本敏感，CoT 必须是有选择地开，而不是默认开。</li></ul><h3 id="_3-3-openai-和-anthropic-官方文档其实都在提醒同一件事" tabindex="-1">3.3 OpenAI 和 Anthropic 官方文档其实都在提醒同一件事 <a class="header-anchor" href="#_3-3-openai-和-anthropic-官方文档其实都在提醒同一件事" aria-label="Permalink to &quot;3.3 OpenAI 和 Anthropic 官方文档其实都在提醒同一件事&quot;">​</a></h3><p>OpenAI 现在的 Prompting 文档也明确提到，不同类型模型的最佳提示方式可能不同，复杂应用应该绑定具体模型快照，并且通过 evals 持续验证 Prompt 表现，而不是假设“这套 Prompt 永远成立”。<a href="https://developers.openai.com/api/docs/guides/prompting" target="_blank" rel="noreferrer">官方文档</a></p><p>这意味着一条很现实的工程原则：</p><blockquote><p>CoT 不是一段可以四处复制的固定咒语，它是一种需要随着模型类型、成本目标和任务复杂度一起调整的策略。</p></blockquote><h3 id="_3-4-一个更稳的-cot-写法" tabindex="-1">3.4 一个更稳的 CoT 写法 <a class="header-anchor" href="#_3-4-一个更稳的-cot-写法" aria-label="Permalink to &quot;3.4 一个更稳的 CoT 写法&quot;">​</a></h3><p>我现在更推荐这样组织 CoT，而不是简单写一句 <code>think step by step</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请按以下顺序完成分析：</span></span>
<span class="line"><span>1. 提取已知事实，不做推断</span></span>
<span class="line"><span>2. 列出适用规则</span></span>
<span class="line"><span>3. 说明规则与事实如何对应</span></span>
<span class="line"><span>4. 给出结论</span></span>
<span class="line"><span>5. 如果信息不足，请明确指出缺失项</span></span></code></pre></div><p>这种写法的好处有三个：</p><ul><li>它不是抽象地要求“思考”，而是限定了思考的骨架；</li><li>它天然适合后续做结构化输出；</li><li>它让错误更容易暴露，你知道模型是事实提取错了，还是规则映射错了。</li></ul><h2 id="_4-自一致性不是-多问几次-而是承认推理路径本身可能不稳定" tabindex="-1">4. 自一致性不是“多问几次”，而是承认推理路径本身可能不稳定 <a class="header-anchor" href="#_4-自一致性不是-多问几次-而是承认推理路径本身可能不稳定" aria-label="Permalink to &quot;4. 自一致性不是“多问几次”，而是承认推理路径本身可能不稳定&quot;">​</a></h2><p>CoT 让模型展开步骤，但还有一个问题没解决：<strong>它展开的那一条路径，未必就是最靠谱的那一条。</strong></p><p>这就是 Self-Consistency 要解决的问题。</p><p>那篇论文的核心思路很漂亮：不要只拿一条贪心解码出来的推理链，而是采样出多条不同推理路径，最后选择最一致的答案。<a href="https://arxiv.org/abs/2203.11171" target="_blank" rel="noreferrer">论文链接</a></p><p>这个思想真正打动人的地方在于，它承认了一件很现实的事：</p><blockquote><p>大模型在复杂问题上，不一定缺“答案”，它更可能缺的是“稳定到同一个答案的路径”。</p></blockquote><h3 id="_4-1-什么场景值得用自一致性" tabindex="-1">4.1 什么场景值得用自一致性 <a class="header-anchor" href="#_4-1-什么场景值得用自一致性" aria-label="Permalink to &quot;4.1 什么场景值得用自一致性&quot;">​</a></h3><p>我会把它留给下面这些场景：</p><ul><li>复杂但可验证的推理题；</li><li>多步计算；</li><li>成本比准确率次要的关键链路；</li><li>可以容忍多次采样，但不能容忍明显错判的任务。</li></ul><h3 id="_4-2-什么场景不值得" tabindex="-1">4.2 什么场景不值得 <a class="header-anchor" href="#_4-2-什么场景不值得" aria-label="Permalink to &quot;4.2 什么场景不值得&quot;">​</a></h3><p>如果你的任务是：</p><ul><li>用户评论分类；</li><li>工单摘要；</li><li>标签抽取；</li><li>FAQ 改写；</li></ul><p>自一致性大多数时候不划算。因为：</p><ul><li>你为了一点稳定性，付出了几倍调用成本；</li><li>延迟大幅上涨；</li><li>但任务本身并没有复杂到值得这样做。</li></ul><p>它更像一个“高价值任务的可靠性增强器”，不是默认配置。</p><h2 id="_5-tot-和-prompt-chaining-真正解决的是-单轮上下文装不下完整工作流" tabindex="-1">5. ToT 和 Prompt Chaining，真正解决的是“单轮上下文装不下完整工作流” <a class="header-anchor" href="#_5-tot-和-prompt-chaining-真正解决的是-单轮上下文装不下完整工作流" aria-label="Permalink to &quot;5. ToT 和 Prompt Chaining，真正解决的是“单轮上下文装不下完整工作流”&quot;">​</a></h2><p>很多 Prompt 教程一讲高级策略，就喜欢一路推到 Tree of Thoughts（ToT）或者 Prompt Chaining，但经常忽略一个前提：这类方法真正有价值的地方，不是显得高级，而是承认<strong>有些任务本来就不适合在一轮里做完</strong>。</p><p>Anthropic 的文档里有一句我很认同的话：即便模型已经有较强的 thinking 能力，当你需要检查中间结果、强制经过某个固定流水线，或者明确分离多个子任务时，显式 prompt chaining 仍然很有用。<a href="https://platform.claude.com/docs/en/build-with-claude/prompt-engineering/claude-prompting-best-practices#chain-complex-prompts" target="_blank" rel="noreferrer">官方文档</a></p><p>这句话其实击中了一个常见误区：</p><p>很多人把多阶段编排理解成“模型不够聪明才需要拆步骤”。恰恰相反，很多时候拆步骤不是为了弥补模型智力，而是为了：</p><ul><li>可追踪；</li><li>可审计；</li><li>可测试；</li><li>可替换某一环；</li><li>可在失败后只重跑局部步骤。</li></ul><h3 id="_5-1-tree-of-thoughts-什么时候真有意义" tabindex="-1">5.1 Tree of Thoughts 什么时候真有意义 <a class="header-anchor" href="#_5-1-tree-of-thoughts-什么时候真有意义" aria-label="Permalink to &quot;5.1 Tree of Thoughts 什么时候真有意义&quot;">​</a></h3><p>ToT 论文里展示的是一种更强的推理方式：模型不只沿着一条链往前，而是会探索多条可能路径，并根据中间评价选择继续走哪条。<a href="https://arxiv.org/abs/2305.10601" target="_blank" rel="noreferrer">论文链接</a></p><p>它的确很有启发性，但你如果把它直接拿来套所有业务系统，很容易走偏。</p><p>因为多数企业任务并不是真的“搜索树问题”。它们更常见的困难是：</p><ul><li>事实来源复杂；</li><li>步骤多；</li><li>每一步有不同系统参与；</li><li>最终输出需要被审查。</li></ul><p>对这类场景来说，很多时候更合适的不是 ToT，而是更朴素的 Prompt Chaining：</p><ol><li>第一步先抽取事实；</li><li>第二步根据事实生成判断草案；</li><li>第三步做校验或重写；</li><li>第四步再输出最终结果。</li></ol><p>这种方式没有 ToT 那么“学术上炫”，但它更像真实业务系统。</p><h2 id="_6-结构化输出-才是-prompt-工程真正进入生产的门槛" tabindex="-1">6. 结构化输出，才是 Prompt 工程真正进入生产的门槛 <a class="header-anchor" href="#_6-结构化输出-才是-prompt-工程真正进入生产的门槛" aria-label="Permalink to &quot;6. 结构化输出，才是 Prompt 工程真正进入生产的门槛&quot;">​</a></h2><p>如果你只把 Prompt 当成聊天技巧，那么 Few-Shot 和 CoT 已经足够让你惊艳一阵子了。</p><p>但如果你要把模型接进真实系统，事情会立刻变得没那么诗意。</p><p>系统不关心你写得多像人，它只关心三件事：</p><ul><li>能不能解析；</li><li>能不能校验；</li><li>能不能接下去处理。</li></ul><p>这就是为什么结构化输出如此关键。</p><h3 id="_6-1-工程里最常见的失败-不是模型-完全答错-而是-半对半坏-系统吃不下" tabindex="-1">6.1 工程里最常见的失败，不是模型“完全答错”，而是“半对半坏，系统吃不下” <a class="header-anchor" href="#_6-1-工程里最常见的失败-不是模型-完全答错-而是-半对半坏-系统吃不下" aria-label="Permalink to &quot;6.1 工程里最常见的失败，不是模型“完全答错”，而是“半对半坏，系统吃不下”&quot;">​</a></h3><p>比如你明明想要：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;risk_level&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;high&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;reasons&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;合同金额异常&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;审批链不完整&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;need_human_review&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>模型却返回：</p><ul><li>JSON 前先写了一段解释；</li><li>枚举值写成了 <code>HIGH RISK</code>；</li><li><code>need_human_review</code> 写成了 <code>&quot;yes&quot;</code>；</li><li>或者干脆多加一个系统没定义的字段。</li></ul><p>这类错误从阅读角度看不严重，但从系统角度看就是不可用。</p><h3 id="_6-2-结构化输出的价值-不只是-方便解析" tabindex="-1">6.2 结构化输出的价值，不只是“方便解析” <a class="header-anchor" href="#_6-2-结构化输出的价值-不只是-方便解析" aria-label="Permalink to &quot;6.2 结构化输出的价值，不只是“方便解析”&quot;">​</a></h3><p>它真正改变的是你处理模型输出的方式：</p><ul><li>可以用 Schema 做前置约束；</li><li>可以做字段级校验；</li><li>可以把失败变成可重试、可降级的系统分支；</li><li>可以把“模型输出”变成软件系统里的正式接口契约。</li></ul><p>OpenAI 现在的文档里其实把这件事放得很前：Prompting 是一门艺术加科学，但如果要稳定落地，就应该尽量把结果放进可评估、可版本化、可复用的体系里，而不是让每次提示都散落在业务代码中。<a href="https://developers.openai.com/api/docs/guides/prompting" target="_blank" rel="noreferrer">官方文档</a></p><h3 id="_6-3-一个常被忽略的点-结构化输出也会反过来提升思考质量" tabindex="-1">6.3 一个常被忽略的点：结构化输出也会反过来提升思考质量 <a class="header-anchor" href="#_6-3-一个常被忽略的点-结构化输出也会反过来提升思考质量" aria-label="Permalink to &quot;6.3 一个常被忽略的点：结构化输出也会反过来提升思考质量&quot;">​</a></h3><p>这件事很有意思。很多人以为结构化输出只是后处理需求，但实际用下来你会发现：</p><p>当你要求模型先输出明确字段，例如：</p><ul><li><code>facts</code></li><li><code>rules</code></li><li><code>decision</code></li><li><code>confidence</code></li><li><code>missing_information</code></li></ul><p>模型本身的思路也会变清楚。因为你在强迫它把原本一团模糊的自然语言组织成几个功能清晰的槽位。</p><p>所以结构化输出并不只是为了机器，很多时候也是在帮模型整理自己。</p><h2 id="_7-一个成熟团队怎么判断-该继续写-prompt-还是该换系统方案" tabindex="-1">7. 一个成熟团队怎么判断“该继续写 Prompt，还是该换系统方案” <a class="header-anchor" href="#_7-一个成熟团队怎么判断-该继续写-prompt-还是该换系统方案" aria-label="Permalink to &quot;7. 一个成熟团队怎么判断“该继续写 Prompt，还是该换系统方案”&quot;">​</a></h2><p>这是我觉得最重要、也最容易被忽略的问题。</p><p>很多团队在模型表现不稳定时，本能反应都是“再改改 Prompt”。但 Prompt 的能力边界其实很明确。</p><h3 id="_7-1-适合继续打磨-prompt-的情况" tabindex="-1">7.1 适合继续打磨 Prompt 的情况 <a class="header-anchor" href="#_7-1-适合继续打磨-prompt-的情况" aria-label="Permalink to &quot;7.1 适合继续打磨 Prompt 的情况&quot;">​</a></h3><ul><li>任务已经足够封闭；</li><li>你主要缺的是判断口径和输出稳定性；</li><li>结果不依赖外部实时数据；</li><li>错误主要来自表达混乱，而不是事实缺失。</li></ul><p>这类问题，Few-Shot、CoT、结构化输出通常都很有效。</p><h3 id="_7-2-不适合继续硬打-prompt-的情况" tabindex="-1">7.2 不适合继续硬打 Prompt 的情况 <a class="header-anchor" href="#_7-2-不适合继续硬打-prompt-的情况" aria-label="Permalink to &quot;7.2 不适合继续硬打 Prompt 的情况&quot;">​</a></h3><p>下面这些问题，如果还只靠 Prompt，基本就是在硬撑：</p><table tabindex="0"><thead><tr><th>问题根源</th><th>更合适的解决方案</th></tr></thead><tbody><tr><td>模型缺少事实</td><td>RAG / File Search / 工具调用</td></tr><tr><td>需要实时数据</td><td>Tool Use</td></tr><tr><td>任务跨多阶段且有中间产物</td><td>Prompt Chaining / 工作流编排</td></tr><tr><td>输出必须严格可用</td><td>Structured Output + 校验</td></tr><tr><td>有高风险副作用</td><td>审批流 / 策略引擎 / 人工复核</td></tr></tbody></table><p>最危险的一种情况是：问题明明是“没有事实”，团队却还在围着 Prompt 疯狂调措辞。最后得出的结论往往不是 Prompt 没用，而是“AI 不可靠”。其实不是 AI 不可靠，而是你把它放到了不属于 Prompt 的问题上。</p><h2 id="_8-一个更像工程实践的落地模板" tabindex="-1">8. 一个更像工程实践的落地模板 <a class="header-anchor" href="#_8-一个更像工程实践的落地模板" aria-label="Permalink to &quot;8. 一个更像工程实践的落地模板&quot;">​</a></h2><p>如果你要为一个真实业务任务设计进阶 Prompt，我建议至少按下面这套顺序思考：</p><h3 id="_8-1-先判断任务类型" tabindex="-1">8.1 先判断任务类型 <a class="header-anchor" href="#_8-1-先判断任务类型" aria-label="Permalink to &quot;8.1 先判断任务类型&quot;">​</a></h3><ul><li>这是分类、抽取、推理，还是规划？</li><li>它依赖外部事实吗？</li><li>最终结果是给人看，还是给系统吃？</li></ul><h3 id="_8-2-再决定用什么策略" tabindex="-1">8.2 再决定用什么策略 <a class="header-anchor" href="#_8-2-再决定用什么策略" aria-label="Permalink to &quot;8.2 再决定用什么策略&quot;">​</a></h3><ul><li>缺口径：加 Few-Shot</li><li>缺中间推导：加 CoT 或分步模板</li><li>缺稳定性：做自一致性或二次校验</li><li>缺可消费性：做结构化输出</li><li>缺事实：改 RAG 或 Tool Use</li></ul><h3 id="_8-3-最后把-prompt-当成-版本化资产-而不是散落文本" tabindex="-1">8.3 最后把 Prompt 当成“版本化资产”，而不是散落文本 <a class="header-anchor" href="#_8-3-最后把-prompt-当成-版本化资产-而不是散落文本" aria-label="Permalink to &quot;8.3 最后把 Prompt 当成“版本化资产”，而不是散落文本&quot;">​</a></h3><p>这是上一轮我自己也做得不够好的地方。</p><p>Prompt 真正进入团队协作后，它不应该是一段“谁想到什么就改什么”的临时文本，而应该像代码一样：</p><ul><li>有版本；</li><li>有评估；</li><li>有样例；</li><li>有回归测试；</li><li>有变更原因。</li></ul><p>OpenAI 的 Prompting 文档现在也在强调这一点：Prompt 应该被版本化、可测试、可复用，而不是每次直接在请求里手搓一大段字符串。<a href="https://developers.openai.com/api/docs/guides/prompting" target="_blank" rel="noreferrer">官方文档</a></p><h2 id="_9-小结-prompt-工程的成熟-不在于更会写-而在于更会分工" tabindex="-1">9. 小结：Prompt 工程的成熟，不在于更会写，而在于更会分工 <a class="header-anchor" href="#_9-小结-prompt-工程的成熟-不在于更会写-而在于更会分工" aria-label="Permalink to &quot;9. 小结：Prompt 工程的成熟，不在于更会写，而在于更会分工&quot;">​</a></h2><p>如果我现在重新概括这篇文章，我会把重点收束成一句话：</p><blockquote><p>进阶 Prompt 不是把命令写得更像咒语，而是把一个问题拆成模型真正能吃下、系统真正能接住的输入结构。</p></blockquote><p>Few-Shot 的价值，在于对齐判例和判断口径；<br> CoT 的价值，在于让复杂问题别再偷懒跳步；<br> 自一致性的价值，在于承认推理路径并不总是稳定；<br> 结构化输出的价值，在于让模型输出从“像答案”变成“可用接口”。</p><p>而真正成熟的工程判断，是知道什么时候继续打磨 Prompt，什么时候干脆承认：这已经不是 Prompt 的工作，而该交给检索、工具和工作流了。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://developers.openai.com/api/docs/guides/prompting" target="_blank" rel="noreferrer">OpenAI Prompting Guide</a></li><li><a href="https://platform.claude.com/docs/en/build-with-claude/prompt-engineering/claude-prompting-best-practices" target="_blank" rel="noreferrer">Anthropic Prompting Best Practices</a></li><li><a href="https://arxiv.org/abs/2201.11903" target="_blank" rel="noreferrer">Chain-of-Thought Prompting Elicits Reasoning in Large Language Models</a></li><li><a href="https://arxiv.org/abs/2203.11171" target="_blank" rel="noreferrer">Self-Consistency Improves Chain of Thought Reasoning in Language Models</a></li><li><a href="https://arxiv.org/abs/2305.10601" target="_blank" rel="noreferrer">Tree of Thoughts: Deliberate Problem Solving with Large Language Models</a></li><li>延伸阅读：<a href="./agent-development.html">智能体开发实战：Tool Use / Function Calling 的工程边界</a></li></ul>`,161)])])}const m=i(o,[["render",r]]);export{u as __pageData,m as default};
